// RUN: objc3c -x objective-c++ -fobjc-version=3 -O0 -fsyntax-only %s
// RUN: objc3c -x objective-c++ -fobjc-version=3 -O2 -fsyntax-only %s
// RUN: objc3c -x objective-c++ -fobjc-version=3 --emit-module INTCXX06.objcmod --emit-interface INTCXX06.obji %s
// RUN: objc3c -x objective-c++ --verify-interface INTCXX06.objcmod INTCXX06.obji %s
struct INTCXX06Token {
    int value;
};

int intcxx06_parse(INTCXX06Token token, const char * _Nonnull text) throws;
int intcxx06_parse_c(INTCXX06Token token,
                     const char * _Nonnull text,
                     id<Error> _Nullable * _Nullable outError);

typedef struct INTCXX06Probe {
    int parsedValue;
    id<Error> _Nullable parsedError;
} INTCXX06Probe;

void intcxx06_run_probe(INTCXX06Token token,
                        const char * _Nonnull text,
                        INTCXX06Probe *probe) {
    probe->parsedError = nil;
    probe->parsedValue = intcxx06_parse_c(token, text, &probe->parsedError);
}
